const SCHEMA = {"type": "object", "additionalProperties": false, "properties": {"cards": {"type": "array", "items": {"type": "object", "additionalProperties": false, "properties": {"id": {"type": "string"}, "codes": {"type": "array", "items": {"type": "string"}}, "reason": {"type": "string"}, "low_confidence": {"type": "boolean"}}, "required": ["id", "codes", "reason", "low_confidence"]}}}, "required": ["cards"]};

